"use client";
// src/components/TopNav.tsx
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { ChevronDown, Menu, LogOut, Settings, User, Mail, Lock, Camera, X, Loader, Check, Sparkles } from "lucide-react";
import { useState, useRef, useEffect, useTransition } from "react";
import { createClient } from "@/lib/supabase/client";
import ChangelogModal from "@/components/ChangelogModal";

const LOGO_SRC = "data:image/png;base64,";

const TABS = [
  { href: "/",          label: "Overview" },
  { href: "/sales",     label: "Vendite" },
  { href: "/stock",     label: "Magazzino" },
  { href: "/templates", label: "Template" },
];

// ── Server actions inline via Supabase client ─────────────────────────────────

export default function TopNav({
  userEmail,
  onMenuToggle,
}: {
  userEmail: string;
  onMenuToggle: () => void;
}) {
  const pathname  = usePathname();
  const router    = useRouter();
  const supabase  = createClient();

  const [dropOpen,     setDropOpen]     = useState(false);
  const [settingsOpen, setSettingsOpen] = useState(false);
  const [changelogOpen, setChangelogOpen] = useState(false);
  const [isDark, setIsDark] = useState<boolean>(false);
  const [activeTab,    setActiveTab]    = useState<"profile"|"email"|"password">("profile");

  // Profile tab
  const [displayName,  setDisplayName]  = useState(userEmail.split("@")[0] || "");
  const [avatarUrl,    setAvatarUrl]    = useState<string | null>(null);
  const [avatarFile,   setAvatarFile]   = useState<File | null>(null);
  const [avatarPreview,setAvatarPreview]= useState<string | null>(null);

  // Email tab
  const [newEmail,     setNewEmail]     = useState("");

  // Password tab
  const [newPass,      setNewPass]      = useState("");
  const [confirmPass,  setConfirmPass]  = useState("");

  // Feedback
  const [isPending,    startTransition] = useTransition();
  const [success,      setSuccess]      = useState("");
  const [error,        setError]        = useState("");

  const dropRef    = useRef<HTMLDivElement>(null);
  const fileRef    = useRef<HTMLInputElement>(null);

  const initials    = userEmail ? userEmail.charAt(0).toUpperCase() : "U";
  const currentName = displayName || userEmail.split("@")[0] || "Utente";

  // Load user metadata on mount
  useEffect(() => {
    supabase.auth.getUser().then(({ data: { user } }) => {
      if (user?.user_metadata?.display_name) {
        setDisplayName(user.user_metadata.display_name);
      }
      if (user?.user_metadata?.avatar_url) {
        setAvatarUrl(user.user_metadata.avatar_url);
      }
    });
  }, []);

  // Listen for mobile settings open event
  useEffect(() => {
    function handleMobileSettings() { setSettingsOpen(true); }
    window.addEventListener("open-settings", handleMobileSettings);
    return () => window.removeEventListener("open-settings", handleMobileSettings);
  }, []);

  // When modal opens, ensure fixed overlay is not clipped by overflow:hidden
  useEffect(() => {
    const shell = document.querySelector(".shell") as HTMLElement | null;
    if (shell) shell.style.overflow = settingsOpen ? "visible" : "";
    const html = document.documentElement;
    if (settingsOpen) {
      html.style.overflow = "visible";
      document.body.style.overflow = "visible";
    } else {
      html.style.overflow = "";
      document.body.style.overflow = "";
    }
  }, [settingsOpen]);

  // Dark mode effect — persiste su localStorage e applica classe html
  useEffect(() => {
    const root = document.documentElement;
    if (isDark) {
      root.classList.add("dark");
      localStorage.setItem("theme", "dark");
    } else {
      root.classList.remove("dark");
      localStorage.setItem("theme", "light");
    }
  }, [isDark]);

  // Al mount, legge localStorage e sincronizza (serve per SSR)
  useEffect(() => {
    const saved = localStorage.getItem("theme");
    if (saved === "dark") setIsDark(true);
    else if (saved === "light") setIsDark(false);
  }, []);

  // Close dropdown on outside click
  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (dropRef.current && !dropRef.current.contains(e.target as Node)) {
        setDropOpen(false);
      }
    }
    if (dropOpen) document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, [dropOpen]);

  // Reset feedback on tab change
  useEffect(() => {
    setSuccess("");
    setError("");
  }, [activeTab]);

  async function handleLogout() {
    await supabase.auth.signOut();
    router.push("/login");
    router.refresh();
  }

  function handleFileChange(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (!file) return;
    setAvatarFile(file);
    const reader = new FileReader();
    reader.onload = (ev) => setAvatarPreview(ev.target?.result as string);
    reader.readAsDataURL(file);
  }

  function handleSaveProfile() {
    setError(""); setSuccess("");
    startTransition(async () => {
      try {
        let finalAvatarUrl = avatarUrl;

        // Upload avatar se selezionato
        if (avatarFile) {
          const { data: { user } } = await supabase.auth.getUser();
          if (!user) throw new Error("Non autenticato");
          const ext  = avatarFile.name.split(".").pop() || "jpg";
          const path = `user-avatars/${user.id}/avatar.${ext}`;
          const { error: upErr } = await supabase.storage
            .from("profile-avatars")
            .upload(path, avatarFile, { upsert: true });
          if (upErr) throw new Error(upErr.message);
          const { data: urlData } = supabase.storage
            .from("profile-avatars")
            .getPublicUrl(path);
          finalAvatarUrl = urlData.publicUrl + `?t=${Date.now()}`;
          setAvatarUrl(finalAvatarUrl);
          setAvatarPreview(null);
          setAvatarFile(null);
        }

        // Aggiorna metadata
        const { error: metaErr } = await supabase.auth.updateUser({
          data: {
            display_name: displayName.trim() || userEmail.split("@")[0],
            avatar_url:   finalAvatarUrl,
          },
        });
        if (metaErr) throw new Error(metaErr.message);
        setSuccess("Profilo aggiornato!");
        router.refresh();
      } catch (e: unknown) {
        setError(e instanceof Error ? e.message : "Errore sconosciuto");
      }
    });
  }

  function handleSaveEmail() {
    setError(""); setSuccess("");
    if (!newEmail.trim() || !newEmail.includes("@")) {
      setError("Inserisci un indirizzo email valido.");
      return;
    }
    startTransition(async () => {
      try {
        const { error: e } = await supabase.auth.updateUser({ email: newEmail.trim() });
        if (e) throw new Error(e.message);
        setSuccess("Email aggiornata! Controlla la tua casella per confermare.");
        setNewEmail("");
      } catch (e: unknown) {
        setError(e instanceof Error ? e.message : "Errore sconosciuto");
      }
    });
  }

  function handleSavePassword() {
    setError(""); setSuccess("");
    if (newPass.length < 6) { setError("La password deve essere di almeno 6 caratteri."); return; }
    if (newPass !== confirmPass) { setError("Le password non coincidono."); return; }
    startTransition(async () => {
      try {
        const { error: e } = await supabase.auth.updateUser({ password: newPass });
        if (e) throw new Error(e.message);
        setSuccess("Password aggiornata!");
        setNewPass(""); setConfirmPass("");
      } catch (e: unknown) {
        setError(e instanceof Error ? e.message : "Errore sconosciuto");
      }
    });
  }

  const inputStyle: React.CSSProperties = {
    width: "100%", padding: "10px 13px",
    background: "#F5F5F5", border: "1px solid #EBEBEB",
    borderRadius: 12, color: "#111111", fontSize: 13,
    fontFamily: "inherit", outline: "none",
    boxSizing: "border-box",
  };
  const labelStyle: React.CSSProperties = {
    fontSize: 11, fontWeight: 600,
    textTransform: "uppercase", letterSpacing: ".05em",
    color: "#888888", display: "block", marginBottom: 6,
  };

  return (
    <>
      <style>{`
        :root {
          --tn-bg: #ffffff;
          --tn-border: #EBEBEB;
          --tn-ink: #111111;
          --tn-slate: #888888;
          --tn-light: #F5F5F5;
          --tn-hover: #F5F5F5;
          --tn-drop-bg: #ffffff;
          --tn-drop-shadow: rgba(0,0,0,.10);
          --tn-pill-bg: #F0F0F0;
          --tn-pill-border: #D0D0D0;
          --tn-modal-bg: #ffffff;
        }
        html.dark {
          --tn-bg: #1c1c1e;
          --tn-border: rgba(255,255,255,.10);
          --tn-ink: #f0f0f0;
          --tn-slate: rgba(255,255,255,.45);
          --tn-light: #0f0f0f;
          --tn-hover: rgba(255,255,255,.07);
          --tn-drop-bg: #1c1c1e;
          --tn-drop-shadow: rgba(0,0,0,.45);
          --tn-pill-bg: rgba(255,255,255,.10);
          --tn-pill-border: rgba(255,255,255,.15);
          --tn-modal-bg: #1c1c1e;
        }
        .topnav {
          display: flex; align-items: center;
          padding: 0 24px; height: 64px; width: 100%;
          background: var(--tn-bg); border-bottom: 1px solid var(--tn-border);
          position: sticky; top: 0; z-index: 50;
          transition: background .35s, border-color .25s;
        }
        .tn-logo {
          display: flex; align-items: center; gap: 9px;
          margin-right: 28px; text-decoration: none;
          color: var(--tn-ink); flex-shrink: 0;
        }
        .tn-mark {
          width: 34px; height: 34px; border-radius: 10px;
          background: var(--tn-ink); display: flex; align-items: center; justify-content: center;
          transition: background .35s;
        }
        .tn-brand { font-size: 16px; font-weight: 800; letter-spacing: -.03em; color: var(--tn-ink); transition: color .25s; }
        .tn-tabs { display: flex; gap: 4px; position: absolute; left: 50%; transform: translateX(-50%); }
        .tn-tab {
          padding: 7px 16px; border-radius: 999px; font-size: 13px;
          font-weight: 500; color: var(--tn-slate); cursor: pointer;
          transition: all .18s; border: none; background: transparent;
          font-family: inherit; text-decoration: none; display: inline-flex; align-items: center;
        }
        .tn-tab:hover { color: var(--tn-ink); background: var(--tn-hover); }
        .tn-tab-active { background: var(--tn-ink); color: var(--tn-bg); font-weight: 600; transition: background .35s, color .25s; }
        .tn-tab-active:hover { background: var(--tn-ink); color: var(--tn-bg); }
        .tn-right { display: flex; align-items: center; gap: 4px; position: relative; margin-left: auto; }
        .tn-user {
          display: flex; align-items: center; gap: 8px;
          padding: 4px 12px 4px 4px; border-radius: 999px;
          border: 1px solid var(--tn-border); margin-left: 8px;
          cursor: pointer; transition: border-color .15s, background .35s;
          background: transparent; font-family: inherit;
        }
        .tn-user:hover { border-color: var(--tn-slate); }
        .tn-user.open { border-color: var(--tn-ink); }
        .tn-avatar {
          width: 32px; height: 32px; border-radius: 50%;
          background: #007782; display: flex; align-items: center; justify-content: center;
          font-size: 13px; font-weight: 700; color: #ffffff;
          border: 1.5px solid rgba(0,0,0,.08); overflow: hidden; flex-shrink: 0;
        }
        .tn-avatar img { width: 100%; height: 100%; object-fit: cover; }
        .tn-name { font-size: 12px; font-weight: 600; color: var(--tn-ink); line-height: 1.2; transition: color .25s; }
        .tn-email { font-size: 10px; color: var(--tn-slate); line-height: 1.2; transition: color .25s; }
        .tn-dropdown {
          position: absolute; top: calc(100% + 10px); right: 0;
          background: var(--tn-drop-bg); border: 1px solid var(--tn-border);
          border-radius: 16px; box-shadow: 0 8px 32px var(--tn-drop-shadow);
          min-width: 200px; padding: 6px; z-index: 200;
          animation: tn-fade .15s ease;
          transition: background .35s, border-color .25s;
        }
        @keyframes tn-fade { from { opacity: 0; transform: translateY(-6px); } to { opacity: 1; transform: translateY(0); } }
        .tn-drop-item {
          display: flex; align-items: center; gap: 10px;
          padding: 9px 12px; border-radius: 10px; cursor: pointer;
          font-size: 13px; font-weight: 500; color: var(--tn-ink);
          border: none; background: transparent; width: 100%;
          font-family: inherit; transition: background .12s, color .25s; text-align: left;
        }
        .tn-drop-item:hover { background: var(--tn-hover); }
        .tn-drop-item.danger { color: #FF4D4D; }
        .tn-drop-item.danger:hover { background: rgba(255,77,77,.06); }
        .tn-drop-divider { height: 1px; background: var(--tn-border); margin: 4px 0; transition: background .25s; }
        .tn-dark-row { display: flex; align-items: center; justify-content: space-between; padding: 8px 12px; }
        .tn-dark-label { font-size: 13px; font-weight: 500; color: var(--tn-ink); transition: color .25s; }
        .tn-pill { width: 52px; height: 28px; border-radius: 14px; background: var(--tn-pill-bg); border: 0.5px solid var(--tn-pill-border); cursor: pointer; position: relative; transition: background .3s, border-color .3s; flex-shrink: 0; padding: 0; }
        .tn-pill.on { background: #111111; border-color: #111111; border-radius: 14px; }
        .tn-pill-thumb { position: absolute; top: 3px; left: 3px; width: 22px; height: 22px; border-radius: 50%; background: #ffffff; transition: transform .3s cubic-bezier(.4,0,.2,1); display: flex; align-items: center; justify-content: center; overflow: hidden; }
        .tn-pill.on .tn-pill-thumb { transform: translateX(24px); }
        .tn-ico-sun { position: absolute; inset: 0; display: flex; align-items: center; justify-content: center; transition: opacity .2s; }
        .tn-ico-moon { position: absolute; inset: 0; display: flex; align-items: center; justify-content: center; transition: opacity .2s; }
        .tn-pill:not(.on) .tn-ico-sun { opacity: 1; }
        .tn-pill:not(.on) .tn-ico-moon { opacity: 0; }
        .tn-pill.on .tn-ico-sun { opacity: 0; }
        .tn-pill.on .tn-ico-moon { opacity: 1; }
        .tn-settings-overlay {
          position: fixed; inset: 0; z-index: 9999;
          background: rgba(0,0,0,.35); backdrop-filter: blur(6px);
          display: flex; align-items: center; justify-content: center; padding: 16px;
        }
        .tn-settings-modal {
          background: var(--tn-modal-bg); border-radius: 20px;
          padding: 0; width: 100%; max-width: 460px;
          box-shadow: 0 24px 60px rgba(0,0,0,.14);
          overflow: hidden; transition: background .35s;
        }
        .tn-settings-header {
          display: flex; align-items: center; justify-content: space-between;
          padding: 20px 24px 0;
        }
        .tn-settings-tabs {
          display: flex; gap: 4px; padding: 16px 24px 0;
          border-bottom: 1px solid var(--tn-border);
        }
        .tn-settings-tab {
          padding: 8px 14px; border-radius: 999px 999px 0 0;
          font-size: 12px; font-weight: 600; cursor: pointer;
          border: none; background: transparent; font-family: inherit;
          color: var(--tn-slate); transition: color .15s; border-bottom: 2px solid transparent;
          margin-bottom: -1px;
        }
        .tn-settings-tab:hover { color: var(--tn-ink); }
        .tn-settings-tab.active { color: var(--tn-ink); border-bottom-color: var(--tn-ink); }
        .tn-settings-body { padding: 24px; }
        .tn-avatar-upload {
          display: flex; align-items: center; gap: 16px; margin-bottom: 20px;
        }
        .tn-avatar-big {
          width: 64px; height: 64px; border-radius: 50%;
          background: #007782; display: flex; align-items: center; justify-content: center;
          font-size: 24px; font-weight: 700; color: #ffffff;
          border: 2px solid rgba(0,0,0,.08); overflow: hidden; flex-shrink: 0; position: relative;
          cursor: pointer;
        }
        .tn-avatar-big img { width: 100%; height: 100%; object-fit: cover; }
        .tn-avatar-big-overlay {
          position: absolute; inset: 0; background: rgba(0,0,0,.45);
          display: flex; align-items: center; justify-content: center;
          opacity: 0; transition: opacity .15s; border-radius: 50%;
        }
        .tn-avatar-big:hover .tn-avatar-big-overlay { opacity: 1; }
        .tn-hamburger {
          display: none; width: 38px; height: 38px; border-radius: 10px;
          align-items: center; justify-content: center;
          color: var(--tn-slate); cursor: pointer; border: none; background: transparent; margin-right: 8px;
        }
        @media (max-width: 860px) {
          .tn-tabs { display: none; }
          .tn-hamburger { display: flex; }
          .tn-user .tn-info { display: none; }
          .topnav { padding: 0 16px; }
        }
        @media (max-width: 480px) { .tn-brand { display: none; } }
      `}</style>

      <header className="topnav" style={{ position: "relative" }}>
        <button className="tn-hamburger" onClick={onMenuToggle}>
          <Menu size={20} />
        </button>

        <Link href="/" className="tn-logo">
          <img src={LOGO_SRC} alt="" style={{ width: 28, height: 28, objectFit: "contain", display: "block", flexShrink: 0 }} />
          <span className="tn-brand">Vinted Assistant Pro</span>
        </Link>

        <nav className="tn-tabs">
          {TABS.map(({ href, label }) => {
            const active = pathname === href;
            return (
              <Link key={href} href={href} className={`tn-tab ${active ? "tn-tab-active" : ""}`}>
                {label}
              </Link>
            );
          })}
        </nav>

        {/* User pill + dropdown */}
        <div className="tn-right" ref={dropRef}>
          <button
            className={`tn-user ${dropOpen ? "open" : ""}`}
            onClick={() => setDropOpen(p => !p)}
          >
            <div className="tn-avatar">
              {(avatarUrl || avatarPreview)
                ? <img src={avatarPreview || avatarUrl!} alt="" />
                : initials}
            </div>
            <div className="tn-info">
              <div className="tn-name">{currentName}</div>
              <div className="tn-email">{userEmail}</div>
            </div>
            <ChevronDown size={14} color="#888888" style={{ transform: dropOpen ? "rotate(180deg)" : "none", transition: "transform .2s" }} />
          </button>

          {dropOpen && (
  <div className="tn-dropdown">
    <button className="tn-drop-item" onClick={() => { setDropOpen(false); setSettingsOpen(true); }}>
      <Settings size={15} color="var(--slate)" strokeWidth={1.8} />
      Impostazioni account
    </button>
    <button className="tn-drop-item" onClick={() => { setDropOpen(false); setChangelogOpen(true); }}>
      <Sparkles size={15} color="var(--slate)" strokeWidth={1.8} />
      Scopri le novità
    </button>
    <div className="tn-drop-divider" />
    <div className="tn-dark-row">
      <span className="tn-dark-label">{isDark ? "Dark mode" : "Light mode"}</span>
      <button className={`tn-pill${isDark ? " on" : ""}`} onClick={() => setIsDark(v => !v)}>
        <div className="tn-pill-thumb">
          <div className="tn-ico-sun">...</div>
          <div className="tn-ico-moon">...</div>
        </div>
      </button>
    </div>
    <div className="tn-drop-divider" />
    <button className="tn-drop-item danger" onClick={handleLogout}>
      <LogOut size={15} strokeWidth={1.8} />
      Esci
    </button>
  </div>
)}
        </div>
      </header>

      {/* ── Settings Modal ── */}
      {settingsOpen && (
        <div className="tn-settings-overlay" onClick={e => { if (e.target === e.currentTarget) setSettingsOpen(false); }}>
          <div className="tn-settings-modal">

            {/* Header */}
            <div className="tn-settings-header">
              <div>
                <div style={{ fontSize: 17, fontWeight: 800, color: "#111111", letterSpacing: "-.02em" }}>Impostazioni account</div>
                <div style={{ fontSize: 12, color: "#888888", marginTop: 2 }}>{userEmail}</div>
              </div>
              <button onClick={() => setSettingsOpen(false)} style={{ width: 32, height: 32, borderRadius: 10, border: "none", background: "#F5F5F5", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", color: "#888888" }}>
                <X size={15} />
              </button>
            </div>

            {/* Tabs */}
            <div className="tn-settings-tabs">
              {([
                { key: "profile",  label: "Profilo",   icon: User },
                { key: "email",    label: "Email",     icon: Mail },
                { key: "password", label: "Password",  icon: Lock },
              ] as const).map(({ key, label, icon: Icon }) => (
                <button
                  key={key}
                  className={`tn-settings-tab ${activeTab === key ? "active" : ""}`}
                  onClick={() => setActiveTab(key)}
                >
                  {label}
                </button>
              ))}
            </div>

            {/* Body */}
            <div className="tn-settings-body">

              {/* ── Profilo ── */}
              {activeTab === "profile" && (
                <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
                  {/* Avatar upload */}
                  <div className="tn-avatar-upload">
                    <div className="tn-avatar-big" onClick={() => fileRef.current?.click()}>
                      {(avatarPreview || avatarUrl)
                        ? <img src={avatarPreview || avatarUrl!} alt="" />
                        : <span style={{ fontSize: 24 }}>{initials}</span>}
                      <div className="tn-avatar-big-overlay">
                        <Camera size={18} color="#fff" />
                      </div>
                    </div>
                    <div>
                      <div style={{ fontSize: 13, fontWeight: 600, color: "#111111", marginBottom: 4 }}>Foto profilo</div>
                      <button
                        onClick={() => fileRef.current?.click()}
                        style={{ fontSize: 12, color: "#888888", border: "1px solid #EBEBEB", background: "#fff", borderRadius: 999, padding: "5px 12px", cursor: "pointer", fontFamily: "inherit" }}
                      >
                        Cambia foto
                      </button>
                      <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleFileChange} />
                    </div>
                  </div>

                  <div>
                    <label style={labelStyle}>Nome visualizzato</label>
                    <input
                      style={inputStyle}
                      value={displayName}
                      onChange={e => setDisplayName(e.target.value)}
                      placeholder={userEmail.split("@")[0]}
                    />
                  </div>

                  {error   && <div style={{ fontSize: 12, color: "#FF4D4D", background: "rgba(255,77,77,.07)", padding: "9px 12px", borderRadius: 10 }}>⚠ {error}</div>}
                  {success && <div style={{ fontSize: 12, color: "#6bb800", background: "#f0fad0", padding: "9px 12px", borderRadius: 10, display: "flex", alignItems: "center", gap: 6 }}><Check size={13} /> {success}</div>}

                  <button
                    onClick={handleSaveProfile}
                    disabled={isPending}
                    style={{ padding: "11px", borderRadius: 999, border: "none", background: "#007782", color: "#ffffff", fontWeight: 700, fontSize: 13, cursor: isPending ? "not-allowed" : "pointer", fontFamily: "inherit", opacity: isPending ? .7 : 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}
                  >
                    {isPending ? <><Loader size={13} style={{ animation: "spin 1s linear infinite" }} /> Salvataggio…</> : "Salva modifiche"}
                  </button>
                </div>
              )}

              {/* ── Email ── */}
              {activeTab === "email" && (
                <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
                  <div style={{ fontSize: 13, color: "#888888", background: "#F5F5F5", borderRadius: 12, padding: "10px 14px" }}>
                    Email attuale: <strong style={{ color: "#111111" }}>{userEmail}</strong>
                  </div>
                  <div>
                    <label style={labelStyle}>Nuova email</label>
                    <input
                      style={inputStyle}
                      type="email"
                      value={newEmail}
                      onChange={e => setNewEmail(e.target.value)}
                      placeholder="nuova@email.com"
                    />
                  </div>
                  <div style={{ fontSize: 11, color: "#888888" }}>
                    Ti verrà inviata una email di conferma al nuovo indirizzo.
                  </div>

                  {error   && <div style={{ fontSize: 12, color: "#FF4D4D", background: "rgba(255,77,77,.07)", padding: "9px 12px", borderRadius: 10 }}>⚠ {error}</div>}
                  {success && <div style={{ fontSize: 12, color: "#6bb800", background: "#f0fad0", padding: "9px 12px", borderRadius: 10, display: "flex", alignItems: "center", gap: 6 }}><Check size={13} /> {success}</div>}

                  <button
                    onClick={handleSaveEmail}
                    disabled={isPending}
                    style={{ padding: "11px", borderRadius: 999, border: "none", background: "#007782", color: "#ffffff", fontWeight: 700, fontSize: 13, cursor: isPending ? "not-allowed" : "pointer", fontFamily: "inherit", opacity: isPending ? .7 : 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}
                  >
                    {isPending ? <><Loader size={13} style={{ animation: "spin 1s linear infinite" }} /> Salvataggio…</> : "Aggiorna email"}
                  </button>
                </div>
              )}

              {/* ── Password ── */}
              {activeTab === "password" && (
                <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
                  <div>
                    <label style={labelStyle}>Nuova password</label>
                    <input
                      style={inputStyle}
                      type="password"
                      value={newPass}
                      onChange={e => setNewPass(e.target.value)}
                      placeholder="••••••••"
                    />
                  </div>
                  <div>
                    <label style={labelStyle}>Conferma password</label>
                    <input
                      style={inputStyle}
                      type="password"
                      value={confirmPass}
                      onChange={e => setConfirmPass(e.target.value)}
                      placeholder="••••••••"
                    />
                  </div>

                  {error   && <div style={{ fontSize: 12, color: "#FF4D4D", background: "rgba(255,77,77,.07)", padding: "9px 12px", borderRadius: 10 }}>⚠ {error}</div>}
                  {success && <div style={{ fontSize: 12, color: "#6bb800", background: "#f0fad0", padding: "9px 12px", borderRadius: 10, display: "flex", alignItems: "center", gap: 6 }}><Check size={13} /> {success}</div>}

                  <button
                    onClick={handleSavePassword}
                    disabled={isPending}
                    style={{ padding: "11px", borderRadius: 999, border: "none", background: "#007782", color: "#ffffff", fontWeight: 700, fontSize: 13, cursor: isPending ? "not-allowed" : "pointer", fontFamily: "inherit", opacity: isPending ? .7 : 1, display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}
                  >
                    {isPending ? <><Loader size={13} style={{ animation: "spin 1s linear infinite" }} /> Salvataggio…</> : "Cambia password"}
                  </button>
                </div>
              )}

            </div>
          </div>
        </div>
      )}

      <style>{`@keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }`}</style>
      {changelogOpen && <ChangelogModal onClose={() => setChangelogOpen(false)} />}
    </>
  );
}
